var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>유기체 감지. 바이탈 체크 실행.</color>","JPN":"<color=#ff3636>有機体感知 バイタルチェック実行。</color>","ENG":"<color=#ff3636>Organic beings detected. Checking vital signs.</color>","TWN":"<color=#ff3636>感應到生物體。執行生命跡象確認。</color>"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_33"},{"id":"L5_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"저건…… 침식체? 아니, 퓨처 앳 워에서 만든 기계 아냐?","JPN":"あれは……侵食体？　いや、フューチャーアットウォーで作った機械じゃないか？","ENG":"Is that... a C.O.? Or a machine made by Future-at-War?","TWN":"那是… 侵蝕體？不，不是天啟兵器製造的機械嗎？"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"글쎄요? 저희 편의점은 별별 물건을 다 취급하지만 저 로봇은 없는데요?","JPN":"さあ、うちのコンビニでは色んな物を扱っていますけど、あのロボットはないですよ？","ENG":"Hm? Our convenience store has many things, but not that robot.","TWN":"這個嘛？我們便利店雖然販賣各式各樣的東西，但好像沒有那個機器人？"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"조, 좋아. 뭐가 됐든 이 린 시엔님의 대활약을 다시 이어나갈 때가 온 것 같군.","JPN":"まぁ、いいか。何であれ、このリン・シエン様の大活躍を再び見せる時が来たようだな。","ENG":"O-okay, I guess it’s time for Lin Xien in action again.","TWN":"好…好吧。總之又到我大展身手的時候囉！"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"물러나세요, 시엔 씨. 객기로 상대할 적이 아닙니다.","JPN":"下がってください、シエンさん。ノリで相手できる敵ではありません。","ENG":"Stay back, Xien. That thing is not to be toyed with.","TWN":"西恩，退下吧。現在不是意氣用事的時候。"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"엥? 어, 왜?","JPN":"え？　なんで？","ENG":"Hm? Um, why?","TWN":"嗯？為什麼？"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"저 기계의 통칭은 모더레이터. 위험도로 평가하면 4종 침식체에 준하는 파괴 병기입니다.","JPN":"あの機械は通称モデレーター。危険度で評価すると第4種侵食体に準ずる破壊兵器です。","ENG":"That is the Moderator. It’s a destructive weapon with a danger level equivalent to a Category 4 C.O.","TWN":"那個機器統稱為仲裁者。是危險程度當於4類侵蝕體的破壞性武器。"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"4종이요? 그렇지만 저건……?","JPN":"第4種ですか？　でもあれは……？","ENG":"Category 4? But it’s...","TWN":"4類？可是…？"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"……훗. 훗훗. 아쉽군. 배를 내놓고 너무 질주했더니 속이 쓰려 오네.","JPN":"……フッフッフッ。残念だな。お腹を出した状態で走りすぎたせいか、お腹が痛くなってきたぞ。","ENG":"...Hah, hah hah. This is regretful. I’ve been exposing my belly for too long, now I’m having a stomachache.","TWN":"…呵呵，真是不湊巧。剛剛騎車時肚子吹到風，現在肚子有點不舒服！"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"이 린 시엔님이 만전의 상태였다면 좋은 승부를 낼 수 있었을 텐데!","JPN":"このリン・シエン様が万全の状態だったらイイ勝負ができたはずなのに！","ENG":"I would have been able to fight it if it wasn’t for this stomachache!","TWN":"要不是我肚子痛，肯定三兩下就打爆它們的！"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>바이탈 체크 완료. 침식 증후군 증상 확인 불가.</color>","JPN":"<color=#ff3636>バイタルチェック完了。侵食症候群の症状確認不可。</color>","ENG":"<color=#ff3636>Vital signs checked. Unable to verify Corruption Syndrome symptoms.</color>","TWN":"<color=#ff3636>生命跡象確認完畢。無法確認侵蝕症候群。</color>"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>침식 위험성 ─── &*#&퍼센트. 소각 필요.</color>","JPN":"<color=#ff3636>侵食危険性 ─── &*#&パーセント。焼却必要。</color>","ENG":"<color=#ff3636>The chances of Corruption ─── &*#& percent. Incineration required.</color>","TWN":"<color=#ff3636>侵蝕危險性 ─── &*#&%。需要燒毀。</color>"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"다른 태스크포스들에게 맡기고 싶지만, 관리국이 발령한 적색 긴급 방어령을 받고 오려면 한세월씩 걸리겠죠.","JPN":"他のタスクフォースカンパニーに任せたいのですが、管理局が発令したパターンレッドの緊急防御令を受けてから来るには間に合いません。","ENG":"I wish there were other TASKFORCE companies to take care of it, but it will be too late if we wait until the Administration issues the red alert and finds someone for the job.","TWN":"雖然想交給其他特遣勢力，但等到管理局發布紅色緊急防備令，需要一個多月的時間吧？"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"무기만 있으면 됩니다. 물론 준비하셨겠죠?","JPN":"武器さえあれば問題ないです。もちろん準備できていますよね？","ENG":"All I need is my weapon. Of course you got it ready, didn’t you?","TWN":"只要劍在手就沒問題，有帶來吧？"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"당연하지! 만약을 대비해 예거 양에게 부탁했다네!","JPN":"当然さ！　念のためイェーガーさんに頼んである。","ENG":"Of course! I asked Ms. Jaegar to bring it just in case.","TWN":"當然囉！以防萬一，我早就拜託拉拉囉！"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자, 라라 양? 주문했던 물건을 받을 수 있겠나?","JPN":"さあ、イェーガーさん。注文した物を渡してくれ。","ENG":"Lara, may I have the package I requested?","TWN":"拉拉？我訂的東西沒問題吧？"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"아 참, 내 정신 좀 봐! 하마터면 정시 배달을 못 했겠어요!","JPN":"あ、そうだ！　うっかりしていました！","ENG":"Oh my! I almost missed the on-time delivery!","TWN":"對吼，我真是的！差點無法準時送達！"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"잠시만요, 여기 이렇게 에어캡으로 포장해 뒀는데…….","JPN":"お待ちください、エアキャップで梱包しておいたんですが……","ENG":"Please wait, I wrapped it with air-cap bubbles...","TWN":"等我一下喔，我明明有把它真空包裝…"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"어? 사람이네?","JPN":"あれ？　人がいる？","ENG":"Oh, it’s a girl!","TWN":"嗯？是個人喔？"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"아빠, 저 사람 좀 봐. 갑자기 차원 균열에서 떨어졌어.","JPN":"パパ、あの人を見て。いきなり次元の亀裂から出てきたの。","ENG":"Daddy, look. A girl fell from the dimensional crack.","TWN":"爸爸，你看那個人，突然掉到次元裂變咧！"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"음? 사람?","JPN":"うん？　人が？","ENG":"Huh? A girl?","TWN":"嗯？人嗎？"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그림자는 아닐 테고, 설마 균열에 휘말린 엑자일러인가?","JPN":"シャドウじゃあるまいし、まさか亀裂に巻き込まれたエグザイラーか？","ENG":"I don’t think it’s a Shadow. Maybe it’s an Exile swept into the crack?","TWN":"應該不是暗影，難道是捲入裂縫的流浪者？"},"stage":{"bg":"VILLAGE1","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"아야야야……. 엉덩이야…….","JPN":"いててて……お尻が……","ENG":"Oww... My bum...","TWN":"唉唷唷唷…我的屁股…"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"여기가 어디야? 멀대랑 스승님은 어디로 가고?","JPN":"ここはどこ？　ヒョロガリと師匠はどこ？","ENG":"Where am I? Where is the Beanstalk and the Master?","TWN":"這裡是哪裡？傻大個跟老闆人呢？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"………………나잖아?","JPN":"…………私？","ENG":"... That’s me.","TWN":"…這不是我嗎？"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L46_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>바이탈 체크 완료. 침식 증후군 증상 확인 불가.</color>","JPN":"<color=#ff3636>バイタルチェック完了。侵食症候群の症状確認不可。</color>","ENG":"<color=#ff3636>Vital signs checked. Unable to verify Corruption Syndrome symptoms.</color>","TWN":"<color=#ff3636>生命跡象確認完畢。無法確認侵蝕症候群。</color>"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"어? 이 커다란 딱정벌레, 어디서 본 것 같은데?","JPN":"あれ？　この大きなカブトムシ、どこかで見た気がするけど？","ENG":"Huh? This giant beetle looks familiar.","TWN":"嗯？這個大甲蟲，好像在哪看過？"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"아, 맞다! 멀대가 저번에 한 번 알려 줬지! 모터레이서!","JPN":"あ、そうだ！　ヒョロガリが確か一度だけ教えてくれた！　モーターレーサー！","ENG":"Oh, yeah! The Beanstalk told me once! The Motoracer!","TWN":"有了啦！上次傻大個有跟我說過！是中才者!"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"모더레이터야! 한 번이 아니라 수십 번은 더 알려 줬다고!","JPN":"モデレーターよ！　一度どころか、数十回は教えてもらったでしょう！","ENG":"It’s Moderator! He told you countless times!","TWN":"是仲裁者！而且應該不只告訴過你一次！"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐, 흥분하지 말게. 부사장. 이름이 뭐가 중요한가.","JPN":"お、落ち着け、副社長。名前など大事なことではない。","ENG":"C-calm down, Vice President. It’s just a name, it’s not that important.","TWN":"不…不要激動，副總，名字不重要！"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"사장님. 이래도 몰래카메라가 아니라고 우기실 작정입니까?","JPN":"社長。これでもドッキリじゃないと言い張るつもりですか？","ENG":"And you’re still insisting that this is not some candid camera trick?","TWN":"老闆，現在你還想騙我這不是在整人嗎？"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"저 한 명 놀리려고 준비를 아주 열심히 하신 것 같군요.","JPN":"私をからかうために、色々と念入りに準備したようですね。","ENG":"I see you worked very hard to make fun of me.","TWN":"為了整我這麼大費周章啊？"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그 깡통부터 부수고 찾으러 가겠습니다. 필사적으로 숨어 계시죠.","JPN":"その缶をぶち壊して、本体を探しに行きます。せいぜい必死に隠れていてくださいね。","ENG":"When I’m done with the tin can, I’m coming for you. So you’d better hide.","TWN":"我要先把那個罐頭打爛，你先拼命躲好吧。"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"설명해 주지!","JPN":"説明するからまってくれ！","ENG":"Let me explain!","TWN":"你先聽我說！"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아무래도 차원계면이 불안정해진 상태에서 예거 양이 가져 온 리액티브 소드가 일종의 촉매로 작용한 것 같네!","JPN":"どうやら次元界面が不安定になった状態で、イェーガーさんが持ってきたリアクティブソードが一種の触媒として作用したようだ。","ENG":"I think the Reactive Sword that Ms. Jaegar brought worked as a catalyst with the unstable dimension surface!","TWN":"現在次元介面不穩定，伊格帶來的反應劍可能起了某種催化作用！"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"워낙 고도의 기술로 만들어졌다 보니 시공간 축에 미묘한 작용을 일으킨 것 같군.","JPN":"あまりにも高度すぎる技術で作られているせいで、時空間軸にわずかな作用を起こしたようだね。","ENG":"It’s a very high-tech weapon, I think it affected the spacetime somehow.","TWN":"畢竟是用尖端技術製造而成的，在時空軸產生微妙作用也是不無可能。"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"겨우 그걸로 제 흑역사가 콕 집어서 나타났다고요? 그 설명을 저더러 믿으라는 겁니까?","JPN":"それだけの理由で私の黒歴史が現れたのですか？　その説明で私に信じろと？","ENG":"So it chose the worst time in my life to appear? You want me to believe that?","TWN":"然後我的黑歷史就這樣蹦出來？你覺得我會相信這麼荒謬的事嗎？"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠. 나한테 따지기보다는 과거의 자네부터 말리는 편이 더 나을 것 같네만.","JPN":"オホン、今は私を問い詰めるより、過去の自分を止めたほうがよさそうだが。","ENG":"I think stopping the past-you should be your priority rather than yelling at me.","TWN":"咳咳，與其拷問我，要不要先攔一下過去的你？"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"좋아, 모터레이서! 이 이수연님 앞에 모습을 드러낸 배짱 하난 인정해 줄게!","JPN":"よし、モーターレーサー！　このカナミ・キズナ様の前に姿を現した度胸だけは認めてあげる！","ENG":"Okay, Motoracer! I commend you for bravely challenging me!","TWN":"很好，中才者！我欣賞你的膽量！"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"멈춰! 이수연! 아무것도 하지 말고 거기 그대로 있어!!","JPN":"待って！　カナミ・キズナ！　何もしないでそのままそこにいて！","ENG":"Stop, Lee Sooyeon! Stop right there, and do nothing!","TWN":"住手，李秀妍！你站在那什麼都別做！！"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"응? 아줌마, 나랑 아는 사이야?","JPN":"うん？　おばさん、私の知り合い？","ENG":"Huh? Old lady, do you know me?","TWN":"嗯？大嬸，你認識我嗎？"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"아줌……?!","JPN":"おば……！？","ENG":"Old lady?!","TWN":"大嬸……？！"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"아무튼 얘기는 나중에! 지금은 저 녀석을 해치우는 게 더 급하니까!","JPN":"とりあえず話はあとで！　今はあいつを倒すのが先なの！","ENG":"I’ll talk to you later! I have to get rid of that thing first!","TWN":"有什麼話等下再說！現在重點是要幹掉那傢伙！"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"지켜봐 주세요, 스승님! 저 이수연이 펜릴 전대의 실력을 보여 줄게요!","JPN":"見守っていてくださいね、師匠！　このカナミ・キズナがフェンリル戦隊の実力を見せつけてやります！","ENG":"Watch me, Master! I, Lee Sooyeon, will show them the power of Fenrir Division!","TWN":"師父，你看著吧！我會讓大家知道芬里爾戰隊的厲害！"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"멈추라면 좀 멈추라고!! 이 왈가닥아!!","JPN":"だから止まれって！！　このじゃじゃ馬！！","ENG":"Why don’t you listen to me? You clueless idiot!","TWN":"我叫你住手！！你這個蕭查某！！"},"stage":{"bg":"VILLAGE1","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};